const root = $json ?? {};
const body = root.body ?? root;
const action = String(body.action ?? '').toLowerCase().trim();

const jiraBaseUrl = String(body.jira_base_url ?? body.jira?.base_url ?? '').trim().replace(/\/$/, '');
const jiraEmail = String(body.jira_email ?? body.jira?.email ?? '').trim();
const jiraToken = String(body.jira_api_token ?? body.jira?.api_token ?? '').trim();

const doc = (text) => ({
  type: 'doc',
  version: 1,
  content: [{ type: 'paragraph', content: [{ type: 'text', text: String(text ?? '') }] }]
});

let requestUrl = '';
let requestBody = {};
let resolvedAction = 'ready';

if (!jiraBaseUrl || !jiraEmail || !jiraToken) {
  resolvedAction = 'invalid_credentials';
} else if (action === 'create_issue') {
  const projectKey = body.project_key ?? body.projectKey ?? '';
  requestUrl = `${jiraBaseUrl}/rest/api/3/issue`;
  requestBody = {
    fields: {
      project: { key: projectKey },
      summary: body.summary ?? 'Untitled issue',
      description: doc(body.description ?? ''),
      issuetype: { name: body.issue_type ?? 'Task' },
      ...(body.labels ? { labels: body.labels } : {}),
      ...(body.parent_key ? { parent: { key: body.parent_key } } : {})
    }
  };
} else if (action === 'list_issues') {
  const projectKey = body.project_key ?? body.projectKey ?? '';
  requestUrl = `${jiraBaseUrl}/rest/api/3/search/jql`;
  requestBody = {
    jql: body.jql ?? (projectKey ? `project=${projectKey} ORDER BY created DESC` : 'ORDER BY created DESC'),
    maxResults: Number(body.limit ?? 20),
    fields: ['summary', 'status', 'issuetype', 'priority', 'assignee', 'created', 'updated']
  };
} else if (action === 'add_comment') {
  const issueKey = body.issue_key ?? body.issueKey ?? '';
  requestUrl = `${jiraBaseUrl}/rest/api/3/issue/${issueKey}/comment`;
  requestBody = { body: doc(body.comment ?? '') };
} else if (action === 'transition_issue') {
  const issueKey = body.issue_key ?? body.issueKey ?? '';
  requestUrl = `${jiraBaseUrl}/rest/api/3/issue/${issueKey}/transitions`;
  requestBody = { transition: { id: String(body.transition_id ?? body.transitionId ?? '') } };
} else if (action === 'link_run') {
  const issueKey = body.issue_key ?? body.issueKey ?? '';
  const runId = body.run_id ?? body.runId ?? '';
  const runBase = String(body.run_base_url ?? '').replace(/\/$/, '');
  const runUrl = runBase && runId ? `${runBase}/runs/${runId}` : '';
  requestUrl = `${jiraBaseUrl}/rest/api/3/issue/${issueKey}/comment`;
  requestBody = { body: doc(`Linked run_id: ${runId}${runUrl ? `\nRun URL: ${runUrl}` : ''}`) };
} else {
  resolvedAction = 'unsupported_action';
}

const authHeader = 'Basic ' + Buffer.from(`${jiraEmail}:${jiraToken}`).toString('base64');

return [{
  json: {
    action,
    resolvedAction,
    shouldCallJira: resolvedAction === 'ready',
    requestUrl,
    requestBody,
    authHeader
  }
}];

return [{
  json: {
    status: 'ok',
    action: $('Normalize Jira Request').first().json.action,
    result: $json
  }
}];

return [{
  json: {
    status: 'error',
    action: $json.action,
    resolvedAction: $json.resolvedAction,
    message: 'Unsupported action or missing Jira credentials in payload'
  }
}];
